<?php
namespace App\Services\Security;use App\Models\{SecurityIncident,User};use Carbon\Carbon;use Illuminate\Validation\ValidationException;
class SecurityIncidentGovernanceService{public function assignOwner(SecurityIncident $i,User $a,User $o,string $r):SecurityIncident{return $this->update($i,$a,['owner_id'=>$o->id],'owner_assigned',$r);}public function assignEscalationOwner(SecurityIncident $i,User $a,User $o,string $r):SecurityIncident{return $this->update($i,$a,['escalation_owner_id'=>$o->id],'escalation_owner_assigned',$r);}public function setDueDate(SecurityIncident $i,User $a,Carbon $d,string $r):SecurityIncident{return $this->update($i,$a,['sla_due_at'=>$d],'due_date_set',$r);}public function getClosureReadiness(SecurityIncident $i):array{$b=[];$w=[];if(in_array($i->severity,['high','critical'],true)&&!$i->owner_id)$b[]='Incident owner is required.';if(in_array($i->severity,['high','critical'],true)&&!$i->escalation_owner_id)$b[]='Escalation owner is required.';if($i->postmortem_required&&!$i->postmortems()->where('status','approved')->exists())$b[]='Approved incident postmortem is required.';if($i->tasks()->whereIn('status',['open','in_progress'])->exists())$b[]='Open incident response tasks must be completed.';if($i->tasks()->where('status','blocked')->exists())$b[]='Blocked incident response tasks prevent closure.';if($i->correctiveActions()->where('verification_required',true)->where('verification_status','!=','verified')->exists())$b[]='Corrective actions require independent verification.';if($i->postmortemReviewCycles()->whereIn('status',['scheduled','in_review'])->exists())$b[]='Open postmortem review cycle prevents closure.';if($i->recurrenceLinks()->where('relation_type','possible_recurrence')->exists())$w[]='Possible recurrence requires review.';if(in_array($i->severity,['high','critical'],true)&&$i->recurrence_status==='recurring'&&!$i->postmortemReviewCycles()->exists())$b[]='Recurring high/critical incident requires a postmortem review cycle.';$i->update(['closure_blockers'=>$b]);return ['ready'=>$b===[],'blockers'=>$b,'warnings'=>$w];}public function approveClosure(SecurityIncident $i,User $a,string $note):SecurityIncident{if(trim($note)==='')throw ValidationException::withMessages(['note'=>'Closure approval note is required.']);$r=$this->getClosureReadiness($i);if(!$r['ready'])throw ValidationException::withMessages(['closure'=>implode(' ',$r['blockers'])]);return $this->update($i,$a,['closure_approved_by_id'=>$a->id,'closure_approved_at'=>now(),'closure_approval_note'=>$note],'closure_approved',$note);}public function resolveWithGovernance(SecurityIncident $i,User $a,string $summary):SecurityIncident{if(!$i->closure_approved_at)throw ValidationException::withMessages(['closure'=>'Governed closure approval is required.']);$r=$this->getClosureReadiness($i);if(!$r['ready'])throw ValidationException::withMessages(['closure'=>implode(' ',$r['blockers'])]);return $this->update($i,$a,['status'=>'resolved','resolved_by_id'=>$a->id,'resolved_at'=>now(),'resolution_summary'=>$summary],'resolved',$summary);}private function update($i,$a,$d,$t,$r){if(trim($r)==='')throw ValidationException::withMessages(['reason'=>'Reason is required.']);$i->update($d);$i->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$r,'created_at'=>now()]);return $i->refresh();}}
